	('3654cae2-5bf8-485a-a085-3effce5298d5', 'Intelligent Internet of Things', 'L''obiettivo del corso di "Intelligent Internet of Things" e'' quello di fornire agli studenti delle
INSERT INTO "catalog"."departments" ("id", "name", "code", "description", "area", "position", "created_at", "updated_at") VALUES
	('c0fd75bf-e93e-441b-a65a-6d53ee4b2551', 'Dipartimento di Economia "Marco Biagi"', 'DEMB', 'Centro di eccellenza dedicato allo studio delle dinamiche economiche, aziendali e sociali, orientato alla formazione di professionisti capaci di interpretare la complessità dei mercati e delle politiche del lavoro.', 'SOCIETA_CULTURA', 0, '2026-03-29 09:52:37.514198+00', '2026-04-11 14:50:56.028206+00'),
	('39f87c50-26f1-4d8c-9886-246c692e3f4c', 'Dipartimento di Comunicazione ed Economia', 'DCE', 'Polo multidisciplinare focalizzato sulla comprensione dei processi comunicativi e dei modelli economici in contesti digitali, con un forte orientamento all''innovazione strategica e al marketing.', 'SOCIETA_CULTURA', 0, '2026-03-29 09:52:37.579325+00', '2026-04-11 14:50:56.028206+00'),
	('be0eeb7b-c23c-4a46-b76c-b0aefa2fea4e', 'Dipartimento di Studi Linguistici e Culturali', 'DSLC', 'Spazio di ricerca e formazione dedicato alla mediazione linguistica e culturale, volto a promuovere il dialogo internazionale e la comprensione delle identità globali attraverso lo studio delle lingue e letterature.', 'SOCIETA_CULTURA', 0, '2026-03-29 09:52:37.645942+00', '2026-04-11 14:50:56.028206+00'),
	('9ad95336-7bc3-4f6c-a753-a7d347aa5eba', 'Dipartimento di Giurisprudenza', 'DGIU', 'Istituzione di consolidata tradizione dedicata all''approfondimento della cultura giuridica, coniugando il rigore degli studi classici con l''analisi delle nuove frontiere del diritto nazionale e internazionale.', 'SOCIETA_CULTURA', 0, '2026-03-29 09:52:37.718498+00', '2026-04-11 14:50:56.028206+00'),
	('78719e7e-10b4-455a-8975-c21214965ad1', 'Dipartimento di Educazione e Scienze Umane', 'DESU', 'Centro di eccellenza per le scienze pedagogiche e psicologiche, impegnato nella ricerca educativa d''avanguardia e nella formazione di figure professionali orientate al benessere sociale e alla crescita della persona.', 'SOCIETA_CULTURA', 0, '2026-03-29 09:52:37.766991+00', '2026-04-11 14:50:56.028206+00'),
	('deb16af7-3976-422d-a4ac-b35878d55006', 'Dipartimento di Scienze Biomediche, Metaboliche e Neuroscienze', 'DSBMN', 'Polo di ricerca biomedica d''avanguardia impegnato nello studio delle basi molecolari della salute, con particolare attenzione alle neuroscienze, al metabolismo e all''integrazione tra scienze di base e applicazioni cliniche.', 'SALUTE', 0, '2026-03-29 09:52:37.357533+00', '2026-04-11 14:50:56.028206+00'),
	('9815405d-203c-4dc2-8edb-c89015f48bd2', 'Dipartimento Chirurgico, Medico, Odontoiatrico e di Scienze Morfologiche con Interesse Trapiantologico, Oncologico e di Medicina Rigenerativa', 'DCHIM', 'Dipartimento focalizzato sulla medicina traslazionale e l''innovazione chirurgica, dedicato allo sviluppo di terapie avanzate e alla ricerca scientifica applicata alla pratica clinica di alta specializzazione.', 'SALUTE', 0, '2026-03-29 09:52:37.412632+00', '2026-04-11 14:50:56.028206+00'),
	('7d3744ff-fc31-49d1-8202-99bd1df4839b', 'Dipartimento di Scienze Mediche e Chirurgiche Materno-Infantili e dell''Adulto', 'DSMCMIA', 'Struttura multidisciplinare orientata alla tutela della salute umana in tutte le sue fasi, con un impegno costante nella ricerca scientifica e nell''eccellenza clinica in ambito medico e chirurgico.', 'SALUTE', 0, '2026-03-29 09:52:37.463686+00', '2026-04-11 14:50:56.028206+00'),
	('094fb85d-f71d-4312-9688-b50ea005394f', 'Dipartimento di Scienze Chimiche e Geologiche', 'DSCG', 'Centro dedicato allo studio della materia e del pianeta, focalizzato sullo sviluppo di soluzioni chimiche sostenibili e sulla comprensione dei sistemi geologici per la tutela del territorio e delle risorse.', 'SCIENZE', 0, '2026-03-29 09:52:36.371274+00', '2026-04-11 14:50:56.028206+00'),
	('35e566d8-69e2-427a-a133-f3b8f95235ab', 'Dipartimento di Scienze Fisiche, Informatiche e Matematiche', 'FIM', 'Polo d''eccellenza per le scienze fondamentali e applicate, dove la ricerca teorica in fisica, matematica e informatica si traduce in innovazione tecnologica e soluzioni computazionali avanzate.', 'SCIENZE', 0, '2026-03-29 09:52:36.678847+00', '2026-04-11 14:50:56.028206+00'),
	('1248cc64-6ca9-4408-8ab1-3bb3eb823811', 'Dipartimento di Scienze della Vita', 'DSV', 'Dipartimento multidisciplinare dedicato allo studio della vita in ogni sua forma, integrando biotecnologie e scienze agrarie per promuovere la sostenibilità ambientale e l''innovazione nel settore agro-alimentare.', 'VITA', 0, '2026-03-29 09:52:35.840413+00', '2026-04-11 14:50:56.028206+00'),
	('935c976e-f322-4757-a6da-361fcee33c3b', 'Dipartimento di Ingegneria "Enzo Ferrari"', 'DIEF', 'Motore di innovazione tecnologica e industriale che coniuga la ricerca ingegneristica avanzata con la formazione di figure tecniche trasversali, operando in stretta sinergia con le eccellenze produttive del territorio.', 'TECNOLOGIA', 0, '2025-08-17 15:53:08.399+00', '2026-04-11 14:50:56.028206+00'),
	('cacea5dd-f03b-4dde-a76b-309acdf733c9', 'Dipartimento di Scienze e Metodi dell''Ingegneria', 'DISMI', 'Polo tecnologico orientato all''eccellenza nei sistemi integrati, dove le competenze ingegneristiche e gestionali convergono per promuovere l''efficienza industriale e l''automazione intelligente.', 'TECNOLOGIA', 0, '2026-03-29 09:52:37.228642+00', '2026-04-11 14:50:56.028206+00');
