	('76e0c183-6ead-45da-b1a4-ea2c904198fa', 'Con ''rete logica'' si intende:', 'MULTIPLE_CHOICE', '["Un livello di astrazione nello studio dei sistemi digitali che fornisce una descrizione a livello di componenti logici elementari, senza dipendere dalla tecnologia utilizzata per la realizzazione del sistema.", "Un insieme di circuiti elettronici progettati per eseguire operazioni aritmetiche e logiche complesse, destinate a determinati tipi di calcoli.", "Un tipo di connessione tra microprocessori o nodi in una rete per facilitare le elaborazioni distribuite, migliorando l''efficienza del sistema.", "Un livello software che si occupa dell''ottimizzazione dei calcoli logici attraverso algoritmi specifici per l''elaborazione dei dati."]', '{"Un livello di astrazione nello studio dei sistemi digitali che fornisce una descrizione a livello di componenti logici elementari, senza dipendere dalla tecnologia utilizzata per la realizzazione del sistema."}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:39.75+00', '2025-08-23 12:17:52.361+00'),
	('a6bdb2f2-6eec-43f7-9758-1eaac7f7f025', 'Se X e Y sono espressioni dell''algebra di Boole, quale delle seguenti espressioni NON È VERA?', 'MULTIPLE_CHOICE', '["La differenza logica di X e Y è un’espressione", "X + X'' = 1", "X · X'' = 0", "X + 0 = X"]', '{"La differenza logica di X e Y è un’espressione"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:39.827+00', '2025-08-23 12:17:52.492+00'),
