	('0cac46c7-ba86-4d44-a370-979aef14b560', 'Il teorema degli elementi nulli prevede che', 'MULTIPLE_CHOICE', '["X + 0 = X", "X · 1 = X", "X · 0 = X", "X + 1 = 1"]', '{"X + 1 = 1"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:40.359+00', '2025-08-23 12:17:53.29+00'),
	('2414645f-6116-495d-80ad-6da0f7251b82', 'Il teorema di complementarietà prevede che', 'MULTIPLE_CHOICE', '["X · X'' = 1", "X + X = X", "X + X'' = 1", "X · X = 0"]', '{"X + X'' = 1"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:40.433+00', '2025-08-23 12:17:53.421+00'),
	('28dd5139-8430-430e-bd97-8876b0b31834', 'Semplificare la seguente espressione utilizzando i teoremi dell''algebra di Boole: A''BC + BCD + ABC'' + A''BC'' + B''CD.', 'MULTIPLE_CHOICE', '["A B + C D", "A C + B D", "A''B + BC'' + CD", "A B C + A'' B C''"]', '{"A''B + BC'' + CD"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:40.507+00', '2025-08-23 12:17:53.555+00'),
	('fba76e14-a8ea-4082-b7d9-217078ae7f88', 'Sia data la funzione logica F(x3,x2,x1,x0) = (100- -100 10-0 101-). Quale delle seguenti è la sua corrispondente sintesi minima SP?', 'MULTIPLE_CHOICE', '["F = x1 x0 + x3 x2'' x1 + x3'' x0", "F = x1'' x0'' + x3 x2 x1 + x3'' x0", "F = x1'' x0'' + x3'' x2 x1'' + x3 x0’", "F = x2 x1 + x3'' x0'' + x3 x1''"]', '{"F = x1'' x0'' + x3'' x2 x1'' + x3 x0’"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:40.582+00', '2025-08-23 12:17:53.688+00'),
	('64ff4d26-25df-4629-9cb7-677e99c3d4d2', 'Quale delle seguenti espressioni logiche è equivalente a F = A B'' + (A + C'' D + A D'') B + A'' C'' D?', 'MULTIPLE_CHOICE', '["F = A B + A'' C D", "F = A + C'' D", "F = A C + B D", "F = A + B'' D"]', '{"F = A + C'' D"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:40.659+00', '2025-08-23 12:17:53.821+00'),
	('6f5637ad-14f0-452d-849c-1b212359ed8b', 'Le funzioni logiche di una sola variabile indipendente sono', 'MULTIPLE_CHOICE', '["Due: buffer e not", "Quattro: massa, buffer, not e Vcc", "Tre: and, or, not", "Cinque: xor, buffer, not, massa e Vcc"]', '{"Quattro: massa, buffer, not e Vcc"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:40.733+00', '2025-08-23 12:17:53.95+00'),
	('5b30e97f-29d6-4843-b279-f58ae407a309', 'L''espressione AB + A''C è equivalente a:', 'MULTIPLE_CHOICE', '["AB + A''C", "AB + A''B", "AB + A''C + BC", "A''B + BC"]', '{"AB + A''C + BC"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:40.808+00', '2025-08-23 12:17:54.081+00'),
	('bf58a284-617e-45b5-a6dd-ada9853130f2', 'Quale formato utilizzano gli Eddystone-URL?', 'MULTIPLE_CHOICE', '["JSON", "URL compressi", "XML", "Protobuf"]', '{"URL compressi"}', '', 'MEDIUM', '2dfc78c5-026c-4c67-b393-3b5dbeb34906', '2025-08-17 20:12:42.97+00', '2025-08-17 20:12:42.97+00'),
	('de3dee45-f006-4a8c-87e4-37a9167f7ca8', 'Detto B l''insieme dei simboli dell''algebra di Boole, una funzione completamente specificata di n variabili', 'MULTIPLE_CHOICE', '["Ha come dominio B alla n e come codominio B alla n.", "Ha come dominio B alla n e come codominio B.", "Ha come dominio B e come codominio B alla n.", "Non ha un dominio specifico."]', '{"Ha come dominio B alla n e come codominio B."}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:40.881+00', '2025-08-23 12:17:54.217+00'),
