	('1e2a2469-0820-48a8-b4ae-9257e2048fdb', 'Nell''algebra di Boole, il teorema di identità prevede che:', 'MULTIPLE_CHOICE', '["X + X = 2X", "X + 0 = X", "X · X'' = 1", "X + 1 = X"]', '{"X + 0 = X"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:41.054+00', '2025-08-23 12:17:54.482+00'),
	('65c10a98-be82-4cf8-a844-8b5d70e9f60a', 'Quale delle seguenti espressioni logiche è equivalente a F = (A'' B C'' + D'')'' (D + C'' A + 1) + A B + A'' B?', 'MULTIPLE_CHOICE', '["F = A B + C D", "F = A + B C", "F = A'' C + B D", "F = B + D"]', '{"F = B + D"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:41.204+00', '2025-08-23 12:17:54.748+00'),
	('9f94440f-e025-4c6e-89c3-2fa0808721ab', 'Quale di queste affermazioni è vera?', 'MULTIPLE_CHOICE', '["Una tabella di verità è un tipo di strumento utilizzato esclusivamente per analizzare funzioni booleane che coinvolgono solo due variabili, non applicabile a funzioni con più ingressi.", "Una tabella di verità è una tabella che associa tutte le possibili combinazioni degli ingressi alle corrispondenti configurazioni delle uscite e indica in modo esaustivo il comportamento della rete logica.", "Una tabella di verità è una tecnica utilizzata solo per rappresentare circuiti combinatori, senza applicazione in circuiti sequenziali o in altre tipologie di reti logiche complesse.", "Le tabelle di verità, sebbene siano fondamentali nella progettazione dei sistemi logici, non sono più utilizzate nei moderni sistemi digitali a causa della crescente complessità dei circuiti."]', '{"Una tabella di verità è una tabella che associa tutte le possibili combinazioni degli ingressi alle corrispondenti configurazioni delle uscite e indica in modo esaustivo il comportamento della rete logica."}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:41.277+00', '2025-08-23 12:17:54.881+00'),
	('aaca4525-cf94-4a8b-950e-029698aa6583', 'Sia data la funzione logica F(x3,x2,x1,x0) = (1010 1100 1010 0000). Quale delle seguenti è la sua corrispondente sintesi minima PS?', 'MULTIPLE_CHOICE', '["F = (x2 + x1'') (x3 + x0)", "F = (x3 + x1) (x2'' + x0'')", "F = (x2 + x0'') (x1 + x3'')", "F = (x2 + x0'') (x2'' + x1'') (x3'' + x2'')"]', '{"F = (x2 + x0'') (x2'' + x1'') (x3'' + x2'')"}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:41.354+00', '2025-08-23 12:17:55.013+00'),
	('6ad96261-8a77-4106-892f-bd94d86ffb0f', 'Un mintermine è:', 'MULTIPLE_CHOICE', '["Il prodotto logico di n letterali ognuno dei quali compare in forma vera o complementata, ma mai in entrambe.", "La somma logica di n variabili indipendenti.", "Una combinazione di AND e OR tra n variabili booleane.", "Un termine dell''algebra di Boole che assume sempre valore 1."]', '{"Il prodotto logico di n letterali ognuno dei quali compare in forma vera o complementata, ma mai in entrambe."}', '', 'MEDIUM', '6b583289-4b53-472b-aeaa-a2e5158b275a', '2025-08-17 20:12:41.427+00', '2025-08-23 12:17:55.144+00'),
