	('71e9fa04-ed4f-43bd-9e0c-60feaf0ff934', 'Un grafo è composto da:', 'MULTIPLE_CHOICE', '["Un insieme di vertici V e un insieme di archi E", "Un insieme di archi E che collegano coppie di vertici in V", "Una matrice di adiacenza W e una matrice di grado D", "Una funzione di peso w: E → ℝ⁺ e una metrica di distanza"]', '{"Un insieme di vertici V e un insieme di archi E","Un insieme di archi E che collegano coppie di vertici in V"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:10.462+00', '2025-09-09 15:07:46.694+00'),
	('44ec56df-c176-4d19-b1f4-e0319614bf43', 'L''Energia di Dirichlet misura:', 'MULTIPLE_CHOICE', '["La distanza tra i cluster", "La regolarità (smoothness) di una funzione", "Il numero di archi nel grafo", "La densità dei punti"]', '{"La regolarità (smoothness) di una funzione"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:10.537+00', '2025-09-09 15:07:46.796+00'),
	('7a583182-5f45-40a2-bf78-128d43adc6b5', 'Il problema del minimum cut può essere riformulato come:', 'MULTIPLE_CHOICE', '["Massimizzare $f^TLf$ soggetto a $\\|f\\|_2 = 1$ e $f \\perp \\mathbf{1}$", "Minimizzare $f^TLf$ soggetto a $f \\in \\{-1,+1\\}^n$ e $\\mathbf{1}^Tf = 0$", "Massimizzare $\\text{tr}(F^TLF)$ dove F è la matrice degli indicatori", "Minimizzare $\\|LF\\|_F^2$ soggetto a $F^TF = I$"]', '{"Minimizzare $f^TLf$ soggetto a $f \\\\in \\\\{-1,+1\\\\}^n$ e $\\\\mathbf{1}^Tf = 0$"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:10.611+00', '2025-09-09 15:07:46.901+00'),
	('81141429-0f85-443a-87da-144faee5e780', 'Il Normalized Cut (Ncut) è definito come:', 'MULTIPLE_CHOICE', '["$\\text{Ncut}(A, B) = \\frac{\\text{cut}(A, B)}{\\text{vol}(A)} \\cdot \\frac{\\text{cut}(A, B)}{\\text{vol}(B)}$", "$\\text{Ncut}(A, B) = \\frac{\\text{cut}(A, B)}{\\text{vol}(A)} + \\frac{\\text{cut}(A, B)}{\\text{vol}(B)}$", "$\\text{Ncut}(A, B) = \\frac{\\text{cut}(A, B)}{\\min(\\text{vol}(A), \\text{vol}(B))}$", "$\\text{Ncut}(A, B) = \\frac{\\text{cut}(A, B)}{\\text{vol}(A)} - \\frac{\\text{cut}(A, B)}{\\text{vol}(B)}$"]', '{"$\\\\text{Ncut}(A, B) = \\\\frac{\\\\text{cut}(A, B)}{\\\\text{vol}(A)} + \\\\frac{\\\\text{cut}(A, B)}{\\\\text{vol}(B)}$"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:10.762+00', '2025-09-09 15:07:47.111+00'),
	('617597da-6c23-44a7-b8c9-14ab7a82e93f', 'Quali sono le strategie principali per il K-way spectral clustering?', 'MULTIPLE_CHOICE', '["Bipartizionamento ricorsivo applicando Fiedler vector iterativamente", "Clustering simultaneo dei primi k autovettori nel nuovo spazio incorporato", "Clustering gerarchico agglomerativo sulla matrice Laplaciana", "Ottimizzazione diretta del RatioCut o NCut multivia"]', '{"Bipartizionamento ricorsivo applicando Fiedler vector iterativamente","Clustering simultaneo dei primi k autovettori nel nuovo spazio incorporato"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:10.836+00', '2025-09-09 15:07:47.215+00'),
	('9c2feb9b-120f-43f1-94c0-fa681491c93d', 'Il costo del taglio (CUT) per bipartizionare un grafo in due sottoinsiemi A e B è:', 'MULTIPLE_CHOICE', '["$\\text{CUT}(A, B) = \\sum_{i \\in A, j \\in A} w_{i,j}$", "$\\text{CUT}(A, B) = \\sum_{i \\in A, j \\in B} w_{i,j}$", "$\\text{CUT}(A, B) = \\sum_{i \\in B, j \\in B} w_{i,j}$", "$\\text{CUT}(A, B) = \\max_{i \\in A, j \\in B} w_{i,j}$"]', '{"$\\\\text{CUT}(A, B) = \\\\sum_{i \\\\in A, j \\\\in B} w_{i,j}$"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:10.91+00', '2025-09-09 15:07:47.317+00'),
	('6085e7d5-5065-403b-be4f-7e8a050f3f9e', 'Parlami della predizione dei salti.', 'SHORT_ANSWER', '["To Do"]', '{"To Do"}', '', 'MEDIUM', '5f27faa1-5cb1-463e-947d-42e248a6b657', '2025-08-17 20:14:16.551+00', '2025-08-23 12:18:09.568+00'),
	('6f1b4c24-b5e1-4528-9fd4-5887d09506dc', 'Secondo il Teorema di Rayleigh, la soluzione del problema mincut corrisponde a:', 'MULTIPLE_CHOICE', '["Il primo autovettore del Laplaciano L con autovalore λ₁ = 0", "Il secondo autovettore del Laplaciano L (Fiedler Vector) con λ₂ > 0", "L''autovettore dominante della matrice di adiacenza W", "L''autovettore generalizzato di Lv = λDv con λ minimo non nullo"]', '{"Il secondo autovettore del Laplaciano L (Fiedler Vector) con λ₂ > 0"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:10.987+00', '2025-09-09 15:07:47.418+00'),
	('6d666d60-ff9a-4fed-8a27-b47204779caa', 'Perché si prende il secondo autovalore più piccolo del Laplaciano e non il primo?', 'MULTIPLE_CHOICE', '["Il primo autovalore λ₁ < 0 per grafi disconnessi", "Il primo autovalore λ₁ = 0 ha autovettore costante v₁ = 𝟙 (non partiziona)", "Il primo autovalore non ha significato geometrico nel grafo", "Il primo autovalore λ₁ = λₘₐₓ > λ₂ (ordinamento decrescente)"]', '{"Il primo autovalore λ₁ = 0 ha autovettore costante v₁ = 𝟙 (non partiziona)"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:11.062+00', '2025-09-09 15:07:47.522+00'),
