	('b9bd9dbc-fb8c-485b-bbf5-46b9bbcb3d2d', 'Il Laplaciano di un grafo in forma matriciale è definito come:', 'MULTIPLE_CHOICE', '["$L = W - D$ (forma non normalizzata)", "$L = D - W$ (Laplaciano combinatoriale)", "$L = D^{-1/2}(D-W)D^{-1/2}$ (Laplaciano normalizzato simmetrico)", "$L = I - D^{-1}W$ (Laplaciano normalizzato del random walk)"]', '{"$L = D - W$ (Laplaciano combinatoriale)"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:11.211+00', '2025-09-09 15:07:47.727+00'),
	('e2c0dd38-3a5a-4e97-a235-e3830f72befe', 'Come è definita la derivata pesata (differenza pesata) sul grafo per un arco orientato $(x_i, x_j) \in E$?', 'MULTIPLE_CHOICE', '["$\\partial_{x_j} f(x_i) := w(x_i, x_j) (f(x_j) - f(x_i))$", "$\\partial_{x_j} f(x_i) := \\sqrt{w(x_i, x_j)} (f(x_j) - f(x_i))$", "$\\partial_{x_j} f(x_i) := (f(x_j) - f(x_i)) / w(x_i, x_j)$", "$\\partial_{x_j} f(x_i) := \\sqrt{w(x_j, x_i)} (f(x_j) - f(x_i))$"]', '{"$\\\\partial_{x_j} f(x_i) := \\\\sqrt{w(x_i, x_j)} (f(x_j) - f(x_i))$"}', '', 'MEDIUM', 'de62ef61-10b7-4678-b47a-4f05e07a79fe', '2025-08-17 20:14:11.285+00', '2025-09-09 15:07:47.829+00'),
