	('842c5d17-9aed-4822-a45d-76a3d99a6cd5', 'Il DNS:', 'MULTIPLE_CHOICE', '["Permette la traduzione dal nome mnemonico di un host in un indirizzo IP e viceversa", "È un meccanismo centralizzato che prevede un solo nameserver globale (unico server centralizzato)", "Permette la traduzione dello username al nome effettivo di un utente", "Prevede l’uso di multipli nameserver distribuiti su scala geografica (gerarchicamente)", "Trasforma URL in indirizzo IP", "Trasforma un indirizzo di posta elettronica in un indirizzo logico", "Trasforma l’indirizzo simbolico di un host in un indirizzo ip", "Può essere usato per trasferire messaggi di posta elettronica, files o risorse web"]', '{"Permette la traduzione dal nome mnemonico di un host in un indirizzo IP e viceversa","Prevede l’uso di multipli nameserver distribuiti su scala geografica (gerarchicamente)","Trasforma l’indirizzo simbolico di un host in un indirizzo ip"}', '', 'MEDIUM', '65ca73ed-d574-413c-905f-039760a8dc69', '2025-08-17 20:14:23.048+00', '2025-08-23 12:38:43.466+00'),
	('c1efa5ac-ff69-425f-b116-7a7c6dfa9db9', 'Per chiudere una connessione TCP', 'MULTIPLE_CHOICE', '["Il client invia un segmento con SYN=1", "Il client invia un segmento RST=1 se deve chiudere immediatamente la connessione", "Il client invia un segmento con FIN=1", "Nessuna delle precedenti affermazioni è corretta", "Usato il flag END nell’header ip", "Può essere usato il flag RST nell’header TCP", "Viene usato il flag SYN nell’header TCP con valore -1 nel numero di sequenza"]', '{"Il client invia un segmento RST=1 se deve chiudere immediatamente la connessione","Il client invia un segmento con FIN=1","Può essere usato il flag RST nell’header TCP"}', '', 'MEDIUM', '65ca73ed-d574-413c-905f-039760a8dc69', '2025-08-17 20:14:23.197+00', '2025-08-23 12:38:43.744+00'),
	('218cc646-ad41-4efb-ab8f-c5dfc223d914', 'Indicare la/e affermazioni vera/e', 'MULTIPLE_CHOICE', '["Un buon amplificatore di tensione ha un’impedenza di ingresso infinita", "Un buon amplificatore di tensione ha un’impedenza di ingresso la più piccola possibile", "Un buon amplificatore di tensione ha un’impedenza di uscita la più piccola possibile", "In un amplificatore il guadagno di corrente è uguale al guadagno di tensione"]', '{"Un buon amplificatore di tensione ha un’impedenza di ingresso infinita","Un buon amplificatore di tensione ha un’impedenza di uscita la più piccola possibile"}', '', 'MEDIUM', '058be271-feb0-4062-af12-9dfab5d461d4', '2025-08-17 20:14:26.077+00', '2025-08-17 20:14:26.077+00'),
