	('e7272a52-5d70-4414-8127-5955ce9b2325', 'Confrontando gli algoritmi di routing Link State e Distance Vector, si può affermare che', 'MULTIPLE_CHOICE', '["Gli algoritmi Distance Vector sono caratterizzati da una velocità di convergenza solitamente inferiore", "Gli algoritmi Link State richiedono maggiore spazio di memorizzazione nei router", "Gli algoritmi Link State offrono maggiore robustezza contro eventuali guasti ai router", "Gli algoritmi Distance Vector producono un overhead di traffico di servizio maggiore"]', '{"Gli algoritmi Distance Vector sono caratterizzati da una velocità di convergenza solitamente inferiore","Gli algoritmi Link State richiedono maggiore spazio di memorizzazione nei router","Gli algoritmi Link State offrono maggiore robustezza contro eventuali guasti ai router"}', '', 'MEDIUM', '65ca73ed-d574-413c-905f-039760a8dc69', '2025-08-17 20:14:24.631+00', '2025-08-23 12:38:46.22+00'),
	('59542495-f947-4bea-91a7-076c0f2b7210', 'Nel frame Ethernet', 'MULTIPLE_CHOICE', '["Il campo indirizzo sorgente contiene l’indirizzo MAC del mittente del frame", "Il campo preambolo serve per sincronizzare gli adattatori dei riceventi con quello del mittente", "Il campo tipo permette di multiplexare i protocolli dello stato di rete", "Il campo indirizzo di destinazione contiene l’indirizzo IP del destinatario del frame"]', '{"Il campo indirizzo sorgente contiene l’indirizzo MAC del mittente del frame","Il campo preambolo serve per sincronizzare gli adattatori dei riceventi con quello del mittente","Il campo tipo permette di multiplexare i protocolli dello stato di rete"}', '', 'MEDIUM', '65ca73ed-d574-413c-905f-039760a8dc69', '2025-08-17 20:14:24.706+00', '2025-08-23 12:38:46.356+00'),
	('d4611799-71db-41f4-9abb-d80a2dcbd77f', 'In un algoritmo di routing di tipo Link State', 'MULTIPLE_CHOICE', '["Tutti i nodi hanno una visione identica e completa dello stato della rete", "Ogni nodo trasmette in modalità broadcast informazioni su identità dei nodi adiacenti e costi dei rispettivi link", "Nessun nodo ha informazioni complete sul costo di tutti i link della rete", "Ogni nodo invia informazioni soltanto ai nodi adiacenti", "È sensibile all’effetto rimbalzo che ne rallenta la convergenza in caso di alterazioni della topologia di rete", "Usa tipicamente l’algoritmo Dijkstra per calcolare le soluzioni di routing", "È sensibile all’effetto rimbalzo che ne rallenta la convergenza in caso di alterazioni della topologia di rete"]', '{"Tutti i nodi hanno una visione identica e completa dello stato della rete","Ogni nodo trasmette in modalità broadcast informazioni su identità dei nodi adiacenti e costi dei rispettivi link","Usa tipicamente l’algoritmo Dijkstra per calcolare le soluzioni di routing"}', '', 'MEDIUM', '65ca73ed-d574-413c-905f-039760a8dc69', '2025-08-17 20:14:24.781+00', '2025-08-23 12:38:46.561+00'),
	('1b393a95-9789-429a-b884-13f663152f38', 'Il resolver nel sistema DNS', 'MULTIPLE_CHOICE', '["È una libreria a livello client che si occupa della risoluzione hostname/IP offrendo la possibilità di interagire con il sistema DNS", "È considerato tipicamente un sistema client-side", "Può utilizzare il file /etc/hosts per evitare interazioni con server DNS esterni", "È una parte del server DNS che si occupa di rispondere alle richieste del client"]', '{"È una libreria a livello client che si occupa della risoluzione hostname/IP offrendo la possibilità di interagire con il sistema DNS","È considerato tipicamente un sistema client-side","Può utilizzare il file /etc/hosts per evitare interazioni con server DNS esterni"}', '', 'MEDIUM', '65ca73ed-d574-413c-905f-039760a8dc69', '2025-08-17 20:14:24.856+00', '2025-08-23 12:38:46.706+00'),
	('21a663c0-a47c-4724-af0d-ef19acccd441', 'Spiegami NAIVE DENSITY ESTIMATOR. scrivi le formule.', 'SHORT_ANSWER', '["$P(x_1, x_2, \\dots, x_k | c) = \\prod_{i=1}^{k} P(x_i | c)$", "$f_{NB}(x) = \\arg\\max_{c \\in Y} \\pi_c \\prod_{d=1}^{k} \\phi_{cd}(x_d)$"]', '{"$P(x_1, x_2, \\\\dots, x_k | c) = \\\\prod_{i=1}^{k} P(x_i | c)$","$f_{NB}(x) = \\\\arg\\\\max_{c \\\\in Y} \\\\pi_c \\\\prod_{d=1}^{k} \\\\phi_{cd}(x_d)$"}', '', 'MEDIUM', 'd67d7f42-d06d-4583-94fc-a3a5a70b0433', '2025-08-17 20:14:32.384+00', '2025-09-09 15:07:51.351+00'),
