	('34131d56-35a1-4bae-bc5c-5c4e052cbe54', 'Cosa è un cookie?', 'MULTIPLE_CHOICE', '["È una tupla di dati inviata dal server al client, che la ritrasmette nelle risposte http successive", "Può essere usato dai server per tenere traccia delle sessioni utente", "È una tupla di dati inviata dal client al server, che la ritrasmette nelle risposte http successive", "È una tupla di dati che il client può utilizzare per identificare pagine web già visitate", "Servono per l’autenticazione dell’utente", "Vengono generati dal client", "Vengono conservati dal server", "Vengono conservati dal client", "Vengono rispediti al server nelle richieste successive da parte del client", "Un attachment codificato di un messaggio di posta elettronica che necessita di un particolare formato MIME per la visualizzazione", "Un particolare codice inviato dal server e conservato ed eventualmente ritrasmesso dal browser nelle richieste successive", "Un virus informatico che viene inviato con la posta elettronica", "Un virus informatico che viene inviato come embedded object HTML", "Un codice speciale che il server può utilizzare per identificare il client", "Sono malware che servono seguire l’upload di dati sensibili degli utenti sui …", "Sono utilizzati sono nella versione 1.0 del protocollo e ora sono deprecati", "Sono gestiti mediante gli header del protocollo http", "Sono utilizzati principalmente nelle pagine web statiche"]', '{"È una tupla di dati inviata dal server al client, che la ritrasmette nelle risposte http successive","Può essere usato dai server per tenere traccia delle sessioni utente","Servono per l’autenticazione dell’utente","Vengono conservati dal client","Vengono rispediti al server nelle richieste successive da parte del client","Un particolare codice inviato dal server e conservato ed eventualmente ritrasmesso dal browser nelle richieste successive","Un codice speciale che il server può utilizzare per identificare il client","Sono gestiti mediante gli header del protocollo http"}', '', 'MEDIUM', '65ca73ed-d574-413c-905f-039760a8dc69', '2025-08-17 20:14:25.549+00', '2025-08-23 12:38:47.808+00'),
	('286dca94-c2b2-4d25-892d-dca22354fa49', 'Il campo FlowID nell’header IPv6', 'MULTIPLE_CHOICE', '["È analogo al campo TOS previsto in IPv4", "Indentifica un flusso di comunicazione (es. connessione TCP)", "È usato solo per interfacciarsi con il livello H2N di tipo MPLS", "Può essere calcolato usando indirizzi IP e numeri di porta degli estremi di una connessione TCP", "Consente di migliorare l’efficienza dell’invio di pacchetti al prezzo di una parziale violazione del principio di separazione tra livelli"]', '{"Indentifica un flusso di comunicazione (es. connessione TCP)","Consente di migliorare l’efficienza dell’invio di pacchetti al prezzo di una parziale violazione del principio di separazione tra livelli"}', '', 'MEDIUM', '65ca73ed-d574-413c-905f-039760a8dc69', '2025-08-17 20:14:25.623+00', '2025-08-23 12:38:47.943+00'),
	('7eff3fa2-8174-4e98-b8de-5364f6489d4a', 'Con riferimento al controllo di flusso e di congestione del protocollo TCP', 'MULTIPLE_CHOICE', '["Il campo window dell’header TCP viene usato solo per il controllo di flusso", "Il controllo di congestione prevede che la congestion window aumenti in assenza di errori e sia ridotta in presenza di congestione", "Il campo window dell’header TCP serve sia per il controllo di flusso sia per il controllo di congestione", "Il controllo di flusso prevede che si indichi la dimensione massima del buffer di ricezione per evitare di trasmettere segmenti troppo grossi"]', '{"Il controllo di congestione prevede che la congestion window aumenti in assenza di errori e sia ridotta in presenza di congestione","Il controllo di flusso prevede che si indichi la dimensione massima del buffer di ricezione per evitare di trasmettere segmenti troppo grossi"}', '', 'MEDIUM', '65ca73ed-d574-413c-905f-039760a8dc69', '2025-08-17 20:14:25.851+00', '2025-08-23 12:38:48.229+00'),
