	('969f9f4f-2094-4983-9cce-684bd98f480b', 'Quale fra le seguenti affermazioni in merito alle caratteristiche di un amplificatore operazionale ideale è sicuramente vera?', 'MULTIPLE_CHOICE', '["Ha un guadagno di tensione infinito", "Ha una resistenza di ingresso nulla", "Ha una resistenza di uscita infinita", "Non è un amplificatore differenziale"]', '{"Ha un guadagno di tensione infinito"}', '', 'MEDIUM', '058be271-feb0-4062-af12-9dfab5d461d4', '2025-08-17 20:14:26.917+00', '2025-08-17 20:14:26.917+00'),
	('019460e0-6214-4b5a-a429-58e1f09d6125', 'Indicare le affermazioni vere', 'MULTIPLE_CHOICE', '["Un amplificatore di tensione ideale deve avere resistenza di ingresso nulla", "Un amplificatore operazionale ideale deve avere resistenza di uscita nulla", "La corrente in uscita da un amplificatore operazionale ideale è nulla", "In un diodo in polarizzazione diretta la corrente è data principalmente dalla diffusione di elettroni e lacune"]', '{"Un amplificatore operazionale ideale deve avere resistenza di uscita nulla","In un diodo in polarizzazione diretta la corrente è data principalmente dalla diffusione di elettroni e lacune"}', '', 'MEDIUM', '058be271-feb0-4062-af12-9dfab5d461d4', '2025-08-17 20:14:27.686+00', '2025-08-17 20:14:27.686+00'),
