	('e8e46e35-6dd2-49a8-a539-244b73db75e2', 'Lo **pseudo-header** utilizzato per il checksum UDP viene trasmesso nella rete?', 'MULTIPLE_CHOICE', '["**No**, viene creato solo in memoria per il calcolo del checksum", "**Sì**, viene sempre trasmesso insieme al segmento UDP", "**Sì**, ma solo nelle comunicazioni TCP", "**Dipende** dalla configurazione del sistema"]', '{"**No**, viene creato solo in memoria per il calcolo del checksum"}', NULL, 'HARD', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 15:59:49.438+00', '2025-08-27 15:59:49.438+00'),
	('8317cc59-6920-4a59-88df-3d59981bbc1d', 'Il campo **HLen** nell''header TCP indica:', 'MULTIPLE_CHOICE', '["La lunghezza del payload in byte", "La lunghezza dell''header in parole da 32 bit", "La lunghezza totale del segmento", "La lunghezza della finestra di ricezione"]', '{"La lunghezza dell''header in parole da 32 bit"}', NULL, 'MEDIUM', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:03:56.471+00', '2025-08-27 16:03:56.471+00'),
	('56844e30-ce1d-4928-aa47-97f0b1c13787', 'Quando il flag **URG** è attivo, i dati urgenti:', 'MULTIPLE_CHOICE', '["Partono sempre dall''inizio del segmento TCP", "Sono sempre alla fine del payload", "Bypassano il buffer standard del destinatario", "Vengono utilizzati per comandi di interruzione come ^C"]', '{"Partono sempre dall''inizio del segmento TCP","Bypassano il buffer standard del destinatario","Vengono utilizzati per comandi di interruzione come ^C"}', NULL, 'HARD', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:03:56.543+00', '2025-08-27 16:03:56.543+00'),
	('3a51b283-3cb2-4d3f-9cc0-67f7337207dd', 'Il **piggybacking** in TCP si riferisce a:', 'MULTIPLE_CHOICE', '["L''uso del campo acknowledgment nei segmenti che trasportano dati", "La frammentazione dei segmenti TCP", "La negoziazione dell''MSS", "La gestione dei dati urgenti"]', '{"L''uso del campo acknowledgment nei segmenti che trasportano dati"}', NULL, 'HARD', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:03:56.608+00', '2025-08-27 16:03:56.608+00'),
	('0356c210-dd53-4490-a2d9-1d2196bbc5f8', 'Il **checksum TCP** viene calcolato su:', 'MULTIPLE_CHOICE', '["Solo l''header TCP", "Solo il payload", "Un pseudo-header che include informazioni IP", "L''intero segmento TCP"]', '{"Un pseudo-header che include informazioni IP","L''intero segmento TCP"}', NULL, 'MEDIUM', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:03:56.762+00', '2025-08-27 16:03:56.762+00'),
