	('87aa9ca5-8fbe-4e3d-b396-6f80fc9fdf11', 'Il **Maximum Segment Lifetime (MSL)** nel TIME_WAIT è tipicamente:', 'MULTIPLE_CHOICE', '["15 secondi", "30 secondi", "60 secondi", "120 secondi"]', '{"30 secondi"}', NULL, 'MEDIUM', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:03:57.326+00', '2025-08-27 16:03:57.326+00'),
