	('f55f17a6-7023-43c2-aa1e-2ca009d08b76', 'La formula per calcolare **AdvertisedWindow** è:', 'MULTIPLE_CHOICE', '["MaxRcvBuffer – ((NextByteExpected-1) - LastByteRead)", "MaxRcvBuffer + LastByteRead", "NextByteExpected - LastByteRead", "MaxRcvBuffer / 2"]', '{"MaxRcvBuffer – ((NextByteExpected-1) - LastByteRead)"}', NULL, 'HARD', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:08:56.838+00', '2025-08-27 16:08:56.838+00'),
