	('176fae79-7af1-465e-9b18-eb8a0fdb0112', 'Quando il destinatario comunica **AdvertisedWindow = 0**, il mittente:', 'MULTIPLE_CHOICE', '["Invia periodicamente segmenti con 1 byte di dati", "Si ferma completamente", "Riduce la dimensione dei segmenti", "Aumenta il timeout"]', '{"Invia periodicamente segmenti con 1 byte di dati"}', NULL, 'MEDIUM', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:08:57.077+00', '2025-08-27 16:08:57.077+00'),
