	('bc3add88-a85a-4647-80e4-06aaa957fc9d', 'I **criteri progettuali** di TCP CUBIC includono:', 'MULTIPLE_CHOICE', '["Scalabilità: cresce rapidamente quando è lontano da W_max", "Stabilità: cresce lentamente vicino al massimo", "Fairness: flussi CUBIC tendono a raggiungere finestra equilibrata", "Semplicità di implementazione"]', '{"Scalabilità: cresce rapidamente quando è lontano da W_max","Stabilità: cresce lentamente vicino al massimo","Fairness: flussi CUBIC tendono a raggiungere finestra equilibrata"}', NULL, 'HARD', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:13:50.406+00', '2025-08-27 16:13:50.406+00'),
	('25178754-53c5-4d33-8968-97e0f9f1fa77', 'Il **buffer bloating** è causato da:', 'MULTIPLE_CHOICE', '["Router con buffer di grandi dimensioni", "Ritardo nell''identificazione della congestione", "Pacchetti accodati invece di scartati", "Aumento significativo della latenza"]', '{"Router con buffer di grandi dimensioni","Ritardo nell''identificazione della congestione","Pacchetti accodati invece di scartati","Aumento significativo della latenza"}', NULL, 'MEDIUM', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:13:50.471+00', '2025-08-27 16:13:50.471+00'),
	('d3ac0a61-ac05-4a09-a283-d59ec2eeeb4f', 'Gli **effetti negativi** del buffer bloating includono:', 'MULTIPLE_CHOICE', '["Crollo del throughput per l''effetto dei ritardi", "Alto tasso di perdita dei pacchetti", "Scarsa reattività rispetto alla congestione", "Miglioramento delle prestazioni"]', '{"Crollo del throughput per l''effetto dei ritardi","Alto tasso di perdita dei pacchetti","Scarsa reattività rispetto alla congestione"}', NULL, 'MEDIUM', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:13:50.532+00', '2025-08-27 16:13:50.532+00'),
	('9cbaac6e-40f7-4953-b13e-d021282e0ecd', '**CoDel (Controlled Delay)** funziona:', 'MULTIPLE_CHOICE', '["Scartando pacchetti che rimangono troppo tempo in coda", "Utilizzando fair queuing invece di una coda unica", "Applicando una funzione di hash sui flussi", "Servendo le code con meccanismo round robin"]', '{"Scartando pacchetti che rimangono troppo tempo in coda","Utilizzando fair queuing invece di una coda unica","Applicando una funzione di hash sui flussi","Servendo le code con meccanismo round robin"}', NULL, 'HARD', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:13:50.612+00', '2025-08-27 16:13:50.612+00'),
