	('2f96d7f9-4edf-4566-8fe2-edf55e14d970', 'Nel grafico della fairness TCP, la **bisettrice** rappresenta:', 'MULTIPLE_CHOICE', '["L''allocazione equa della banda tra i flussi", "La linea di saturazione del canale", "Il punto di congestione", "La capacità massima del link"]', '{"L''allocazione equa della banda tra i flussi"}', NULL, 'MEDIUM', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:13:50.814+00', '2025-08-27 16:13:50.814+00'),
	('17501bc7-3ced-4d45-bebc-92f016eb4854', 'Le **differenze principali** tra UDP e TCP includono:', 'MULTIPLE_CHOICE', '["TCP richiede three-way handshake, UDP no", "TCP mantiene stato di connessione, UDP è stateless", "UDP ha overhead minore (8 byte vs 20 byte)", "UDP è sempre più veloce di TCP"]', '{"TCP richiede three-way handshake, UDP no","TCP mantiene stato di connessione, UDP è stateless","UDP ha overhead minore (8 byte vs 20 byte)"}', NULL, 'EASY', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:13:50.889+00', '2025-08-27 16:13:50.889+00'),
