	('bc9e4f9c-85c9-456c-87db-d157218e772a', 'Il **problema di fairness** di TCP BIC è dovuto a:', 'MULTIPLE_CHOICE', '["Dipendenza dal round-trip time (RTT)", "Aggiornamento della finestra a ogni RTT", "Flussi con RTT basso che conquistano più banda", "Flussi con RTT alto che restano penalizzati"]', '{"Dipendenza dal round-trip time (RTT)","Aggiornamento della finestra a ogni RTT","Flussi con RTT basso che conquistano più banda","Flussi con RTT alto che restano penalizzati"}', NULL, 'HARD', '2ececc56-1ffc-4c49-afdf-e0e06a0d1926', '2025-08-27 16:13:51.123+00', '2025-08-27 16:13:51.123+00'),
